previewCss:
.darma-loader-darma-custom-565 {color: var(--loader-color, #b45309);
  --loader-secondary-color: #fcd34d;
  --loader-bg: #ffffff;
   width: 70px;
   height: 26px;
   background: var(--loader-color, #b45309);
   border-radius: 50px;
   --c:no-repeat radial-gradient(farthest-side,currentColor 92%,#0000);
   --s:18px 18px;
   -webkit-mask: var(--c) left 4px top 50%, var(--c) center, var(--c) right 4px top 50%, linear-gradient(currentColor 0 0);
   -webkit-mask-composite:xor;
   mask-composite:exclude;
   animation: darma-loader-darma-custom-565-l1 1.5s infinite;
}
@keyframes darma-loader-darma-custom-565-l1  {
  0% {-webkit-mask-size:0 0 ,0 0 ,0 0 ,auto}
16.67%{-webkit-mask-size:var(--s),0 0 ,0 0 ,auto}
33.33%{-webkit-mask-size:var(--s),var(--s),0 0 ,auto}
50% {-webkit-mask-size:var(--s),var(--s),var(--s),auto}
66.67%{-webkit-mask-size:0 0 ,var(--s),var(--s),auto}
83.33%{-webkit-mask-size:0 0 ,0 0 ,var(--s),auto}
100% {-webkit-mask-size:0 0 ,0 0 ,0 0 ,auto}
}

